var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"금일 22시 30분을 기점으로 요인 구출 작전을 성공적으로 종료했습니다.","JPN":"本日22時30分をもって、要人救出作戦を見事完遂しました。","ENG":"As of 22:30 today, you've successfully completed the mission to secure the V.I.P.","TWN":"今日22時30分芬里爾小隊完成救出要員作戰。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모두들 수고하셨습니다.","JPN":"皆さん、お疲れ様でした。","ENG":"Great work, everyone.","TWN":"各位辛苦了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"거기다가 탈출 루트에서 만난 제 3종 침식체까지 격파하셨군요.","JPN":"脱出ルートで遭遇した第3種侵食体まで撃破しましたね。","ENG":"You even destroyed the Category 3 C.O. on your way out.","TWN":"並且各位在撤離途中，還擊敗了遭遇的3級侵蝕體。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"덕분에 조금 전, 관리국 행정실로부터 감사패까지 도착했습니다.","JPN":"おかげさまで、先ほど管理局行政室から感謝トロフィーが届きました。","ENG":"Thanks to you, the Administration sent us a plaque of appreciation just now.","TWN":"不久前管理局行政室送來了感謝狀，這都是各位的功勞。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"살다 보니 이런 날이 또 오네요.","JPN":"こんな日が来るなんて、思いもよりませんでした。","ENG":"What a crazy day.","TWN":"沒想到在我活著的時候能見到這一天。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"공백기간이 꽤 길어서 걱정을 좀 했었는데.......","JPN":"ブランク期間が長いのが気がかりでしたが……","ENG":"I was a bit worried that you'd be rusty by now...","TWN":"師父這麼久沒有參加小隊作戰，本來我還很擔心呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"역시 기본 실력이 어딜 가진 않는군요.","JPN":"やはり腕が衰えることはなかったですね。","ENG":"But it looks like you still got game.","TWN":"但果然師父的實力還在。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"훌륭합니다, 스승님.","JPN":"すばらしいです、師匠。","ENG":"That was excellent, Master.","TWN":"非常優秀的作戰，師父。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......잠깐만.","JPN":"……ちょっと待て。","ENG":"...Wait.","TWN":"……等一下。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"할말은 많지만 일단 제일 중요한 것부터 짚고 넘어가지.","JPN":"言いたいことは山々だが、一番大事なことから聞こう。","ENG":"I have a lot to say, but I'll start with the most important thing.","TWN":"雖然我有很多話要說，總之先從最重要的開始吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"짧게 해 주시면 좋겠군요. 밀린 서류가 많아서.","JPN":"手短にお願いしますね。確認する書類が溜まっているので。","ENG":"Can we make it quick? I have a lot of paperwork to do.","TWN":"希望您能長話短說，我還有很多文件沒處理。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......대체 저건 뭐야?","JPN":"……いったい、あれは何なんだ？","ENG":"What the heck is that thing?","TWN":"……那到底是什麼啊？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_QM","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"음? 설명 듣지 못하셨나요?","JPN":"あら？ 説明を聞いていませんか？","ENG":"Huh? Didn't you hear?","TWN":"嗯？您沒有聽到之前的說明嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_QM","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 분은 최첨단 과학기술로 만들어진 대인기피용 원격조작 머시노이드 인터페이스......","JPN":"あの方は、最先端の科学技術で作られた対人忌避用の半自律遠隔操作マシンノイド・インターフェース……","ENG":"He's a remote controlled machinoid interface that was developed with state-of-the-art scientific technology...","TWN":"這位是尖端科學和技術結合的超人氣半自動遠端操控機械介面……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_QM","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니! 누가 그딴 설명을 듣고 싶다고 했어?!","JPN":"違う！誰がそんな説明を聞きたいって言った！？","ENG":"No! I don't care what it says on the brochure!","TWN":"不是，誰要聽這種說明啊？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 저게 뭔데 우리더러 이 고생을 하면서 구출해 오라고 했냐고?!","JPN":"あれに、私たちが命がけで救出するほどの価値があるのか聞いてるんだ！","ENG":"Why was that thing so important that you had to put us through all that?!","TWN":"那到底是什麼東西啊？要我們費這麼大勁把它救出來？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아, 그게 궁금하셨군요.","JPN":"あ、それが気になられたと。","ENG":"Oh! That's what you're so curious about.","TWN":"啊，您是想知道這個呀。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};